// Public-facing worker (public-worker.js)
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    
    // Validate request origin and headers
    const allowedOrigins = env.ALLOWED_ORIGINS ? env.ALLOWED_ORIGINS.split(',') : ['*'];
    const origin = request.headers.get('Origin');
    
    if (allowedOrigins[0] !== '*' && origin && !allowedOrigins.includes(origin)) {
      return new Response('Forbidden', { status: 403 });
    }

    // Rate limiting check
    const clientIP = request.headers.get('CF-Connecting-IP');
    const rateLimitKey = `rate_limit:${clientIP}`;
    
    if (env.RATE_LIMITER) {
      const { success } = await env.RATE_LIMITER.limit({ key: rateLimitKey });
      if (!success) {
        return new Response('Too Many Requests', { status: 429 });
      }
    }

    // Request validation
    if (request.method !== 'GET' && request.method !== 'POST' && request.method !== 'PUT' && request.method !== 'DELETE') {
      return new Response('Method Not Allowed', { status: 405 });
    }

    // Add security headers to internal request
    const internalHeaders = new Headers(request.headers);
    internalHeaders.set('X-Internal-Request', 'true');
    internalHeaders.set('X-Request-ID', crypto.randomUUID());
    internalHeaders.set('X-Client-IP', clientIP);
    internalHeaders.delete('Cookie'); // Remove sensitive cookies before forwarding
    
    // Route to appropriate internal worker based on path
    let response;
    
    try {
      if (url.pathname.startsWith('/api/auth')) {
        response = await env.AUTH_SERVICE.fetch(new Request(request.url, {
          method: request.method,
          headers: internalHeaders,
          body: request.body,
          redirect: 'manual'
        }));
      } else if (url.pathname.startsWith('/api/data')) {
        response = await env.DATA_SERVICE.fetch(new Request(request.url, {
          method: request.method,
          headers: internalHeaders,
          body: request.body,
          redirect: 'manual'
        }));
      } else if (url.pathname.startsWith('/api/process')) {
        response = await env.PROCESSING_SERVICE.fetch(new Request(request.url, {
          method: request.method,
          headers: internalHeaders,
          body: request.body,
          redirect: 'manual'
        }));
      } else {
        return new Response('Not Found', { status: 404 });
      }

      // Add security headers to response
      const secureResponse = new Response(response.body, response);
      secureResponse.headers.set('X-Content-Type-Options', 'nosniff');
      secureResponse.headers.set('X-Frame-Options', 'DENY');
      secureResponse.headers.set('X-XSS-Protection', '1; mode=block');
      secureResponse.headers.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
      secureResponse.headers.set('Content-Security-Policy', "default-src 'self'");
      secureResponse.headers.delete('X-Internal-Request');
      
      if (origin && allowedOrigins.includes(origin)) {
        secureResponse.headers.set('Access-Control-Allow-Origin', origin);
        secureResponse.headers.set('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
        secureResponse.headers.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
      }

      return secureResponse;
    } catch (error) {
      console.error('Error forwarding request:', error);
      return new Response('Internal Server Error', { status: 500 });
    }
  }
};

// Auth Service Worker (auth-service.js)
export default {
  async fetch(request, env, ctx) {
    // Verify internal request
    if (request.headers.get('X-Internal-Request') !== 'true') {
      return new Response('Forbidden - Direct access not allowed', { status: 403 });
    }

    const url = new URL(request.url);
    const requestId = request.headers.get('X-Request-ID');

    try {
      if (url.pathname === '/api/auth/login' && request.method === 'POST') {
        const body = await request.json();
        
        // Input validation
        if (!body.username || !body.password) {
          return new Response(JSON.stringify({ error: 'Missing credentials' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        // Sanitize inputs
        const username = String(body.username).slice(0, 100);
        const password = String(body.password).slice(0, 100);

        // Verify credentials (example - use proper auth in production)
        const userKey = `user:${username}`;
        const storedUser = env.AUTH_KV ? await env.AUTH_KV.get(userKey, 'json') : null;

        if (!storedUser) {
          return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
            status: 401,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        // Verify password hash
        const passwordMatch = await verifyPassword(password, storedUser.passwordHash);
        
        if (!passwordMatch) {
          return new Response(JSON.stringify({ error: 'Invalid credentials' }), {
            status: 401,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        // Generate secure token
        const token = await generateSecureToken(username, env.JWT_SECRET);

        return new Response(JSON.stringify({ 
          token,
          user: { username: storedUser.username, id: storedUser.id }
        }), {
          status: 200,
          headers: { 
            'Content-Type': 'application/json',
            'X-Request-ID': requestId
          }
        });
      } else if (url.pathname === '/api/auth/verify' && request.method === 'POST') {
        const body = await request.json();
        
        if (!body.token) {
          return new Response(JSON.stringify({ error: 'Missing token' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const verified = await verifyToken(body.token, env.JWT_SECRET);
        
        if (!verified) {
          return new Response(JSON.stringify({ error: 'Invalid token' }), {
            status: 401,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        return new Response(JSON.stringify({ valid: true, user: verified }), {
          status: 200,
          headers: { 
            'Content-Type': 'application/json',
            'X-Request-ID': requestId
          }
        });
      }

      return new Response('Not Found', { status: 404 });
    } catch (error) {
      console.error('Auth service error:', error);
      return new Response(JSON.stringify({ error: 'Internal server error' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function verifyPassword(password, hash) {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  return hashHex === hash;
}

async function generateSecureToken(username, secret) {
  const header = { alg: 'HS256', typ: 'JWT' };
  const payload = {
    username,
    iat: Math.floor(Date.now() / 1000),
    exp: Math.floor(Date.now() / 1000) + 3600
  };

  const encodedHeader = btoa(JSON.stringify(header)).replace(/=/g, '');
  const encodedPayload = btoa(JSON.stringify(payload)).replace(/=/g, '');
  const signatureInput = `${encodedHeader}.${encodedPayload}`;

  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );

  const signature = await crypto.subtle.sign('HMAC', key, encoder.encode(signatureInput));
  const encodedSignature = btoa(String.fromCharCode(...new Uint8Array(signature))).replace(/=/g, '');

  return `${signatureInput}.${encodedSignature}`;
}

async function verifyToken(token, secret) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;

    const payload = JSON.parse(atob(parts[1]));
    
    if (payload.exp < Math.floor(Date.now() / 1000)) {
      return null;
    }

    const signatureInput = `${parts[0]}.${parts[1]}`;
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['verify']
    );

    const signature = Uint8Array.from(atob(parts[2]), c => c.charCodeAt(0));
    const valid = await crypto.subtle.verify('HMAC', key, signature, encoder.encode(signatureInput));

    return valid ? payload : null;
  } catch {
    return null;
  }
}

// Data Service Worker (data-service.js)
export default {
  async fetch(request, env, ctx) {
    // Verify internal request
    if (request.headers.get('X-Internal-Request') !== 'true') {
      return new Response('Forbidden - Direct access not allowed', { status: 403 });
    }

    const url = new URL(request.url);
    const requestId = request.headers.get('X-Request-ID');

    try {
      // Authenticate request via auth service
      const authHeader = request.headers.get('Authorization');
      if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return new Response(JSON.stringify({ error: 'Unauthorized' }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const token = authHeader.substring(7);
      const authRequest = new Request('http://internal/api/auth/verify', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Internal-Request': 'true',
          'X-Request-ID': requestId
        },
        body: JSON.stringify({ token })
      });

      const authResponse = await env.AUTH_SERVICE.fetch(authRequest);
      if (!authResponse.ok) {
        return new Response(JSON.stringify({ error: 'Unauthorized' }), {
          status: 401,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      const authData = await authResponse.json();

      if (url.pathname === '/api/data/get' && request.method === 'GET') {
        const dataKey = url.searchParams.get('key');
        
        if (!dataKey || !/^[a-zA-Z0-9_-]+$/.test(dataKey)) {
          return new Response(JSON.stringify({ error: 'Invalid key' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const data = env.DATA_KV ? await env.DATA_KV.get(`data:${authData.user.username}:${dataKey}`) : null;

        return new Response(JSON.stringify({ data }), {
          status: 200,
          headers: { 
            'Content-Type': 'application/json',
            'X-Request-ID': requestId
          }
        });
      } else if (url.pathname === '/api/data/set' && request.method === 'POST') {
        const body = await request.json();
        
        if (!body.key || !body.value) {
          return new Response(JSON.stringify({ error: 'Missing key or value' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const dataKey = String(body.key).slice(0, 100);
        if (!/^[a-zA-Z0-9_-]+$/.test(dataKey)) {
          return new Response(JSON.stringify({ error: 'Invalid key format' }), {
            status: 400,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        const dataValue = JSON.stringify(body.value).slice(0, 10000);

        if (env.DATA_KV) {
          await env.DATA_KV.put(`data:${authData.user.username}:${dataKey}`, dataValue);
        }

        return new Response(JSON.stringify({ success: true }), {
          status: 200,
          headers: { 
            'Content-Type': 'application/json',
            'X-Request-ID': requestId
          }
        });
      }

      return new Response('Not Found', { status: 404 });
    } catch (error) {
      console.error('Data service error:', error);
      return new Response(JSON.stringify({ error: 'Internal server error' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

